select count(*) from postgres.comments as c, postgres.posts as p, postgres.votes as v, postgres.badges as b, postgres.users as u where u.id =c.userid and c.userid = p.owneruserid and p.owneruserid = v.userid and v.userid = b.userid and c.score=1 and p.score>=-1 and p.score<=29 and p.creationdate>=timestamp '2010-07-19 20:40:36' and p.creationdate<=timestamp '2014-09-10 20:52:30' and v.bountyamount<=50 and b."date"<=timestamp '2014-08-25 19:05:46' and u.downvotes<=11 and u.creationdate>=timestamp '2010-07-31 17:32:56' and u.creationdate<=timestamp '2014-09-07 16:06:26';
